    fixture: {
      name: "keep-latest-per-workflow",
      now: NOW_ISO,
      dryRun: false,
      policy: { keepLatestPerWorkflow: 2 },
      artifacts: [
        { id: "A-1", name: "art", sizeBytes: 100, createdAt: daysAgo(5), workflowRunId: "wf-A" },
        { id: "A-2", name: "art", sizeBytes: 100, createdAt: daysAgo(3), workflowRunId: "wf-A" },
        { id: "A-3", name: "art", sizeBytes: 100, createdAt: daysAgo(1), workflowRunId: "wf-A" },
        { id: "B-1", name: "art", sizeBytes: 100, createdAt: daysAgo(2), workflowRunId: "wf-B" },
      ],
    },
    expected: {
      deletedCount: 1,
      retainedCount: 3,
      bytesReclaimed: 100,
      totalArtifacts: 4,
      dryRun: false,
      deletedIds: ["A-1"],
    },
  },
  {
    name: "size-cap",
    fixture: {
      name: "size-cap",
      now: NOW_ISO,
      dryRun: true,
      policy: { maxTotalSizeBytes: 150 },
      artifacts: [
        { id: "oldest", name: "big", sizeBytes: 100, createdAt: daysAgo(10), workflowRunId: "wf-A" },
        { id: "middle", name: "big", sizeBytes: 100, createdAt: daysAgo(5), workflowRunId: "wf-A" },
        { id: "newest", name: "big", sizeBytes: 100, createdAt: daysAgo(1), workflowRunId: "wf-A" },
      ],
    },
    expected: {
      deletedCount: 2,
      retainedCount: 1,
